"""
MKT Original Commentary — Proverbs chapters 7–9
Run: python3 scripts/zc-original-proverbs-7-9.py

Source data used:
- data/interlinear/proverbs.json
- data/translation/glossary-hebrew.json
- data/translation/notes/proverbs.json
- data/translation/draft/mediating/proverbs.json

Key decisions in this range:
- Prov 8:22 qanani: MKT renders 'possessed me' — the verb qanah in Hiphil means
  'acquire/possess'; the creationist reading ('created') requires a secondary
  semantic shift; possessed is the primary sense and 'beginning of his way' (reshit
  darko) does not require a temporal ontological claim; both readings left open in commentary
- Prov 8:30 'amon: MKT renders 'master craftsman' — the two main candidates are
  (a) 'amon = craftsman/artisan (cf. Jer 52:15; Song 7:2 Heb) or (b) 'amon =
  ward/nursling (Num 11:12; 2 Sam 4:4); 'master craftsman' maintains the active
  creative-colleague role that fits the syntactic context; commentary notes both options
- Ch 7: the seductress's zebach (peace-offering, v14) is a specific cultic detail —
  Levitical regulations meant leftover meat from the shelamim must be eaten within
  two days (Lev 7:16), so the invitation exploits the abundance of sacrificial meat
- Ch 9: 'eshet kesilot (v13) = 'woman Folly' — a personified anti-Wisdom figure
  mirroring the personified Wisdom of ch 8-9; the parallelism is intentional
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

PROVERBS = {
  "7": {
    "1": "<p><strong>imrei</strong> (<em>'emer</em>, H561) — the plural noun for &lsquo;words, sayings&rsquo;; distinct from <em>dabar</em> (the weightier spoken word or event). The father&rsquo;s instruction is characterized as <em>'emer</em> — the lighter communicative word — yet these words are to be &ldquo;stored up&rdquo; (<em>tzaphan</em>, to hide/treasure, used of hiding valuables). The contrast between the casual word-form and the precious storage-command creates the tone of the entire chapter.</p>",
    "2": "<p><strong>ke-'ishon 'einecha</strong> — &ldquo;as the <em>'ishon</em> of your eye.&rdquo; <em>'Ishon</em> (H380) means &lsquo;pupil of the eye&rsquo; but literally translates as &lsquo;the little man&rsquo; — the tiny reflection of oneself visible in another&rsquo;s pupil. The idiom of guarding like the pupil of the eye appears in Deut 32:10 and Ps 17:8 of YHWH&rsquo;s care for Israel; here the father uses it of the son&rsquo;s care for the father&rsquo;s teaching. The most reflexively sensitive organ of the body.</p>",
    "3": "<p><strong>qashor 'al-'etzbe'otecha</strong> — bind on your fingers. <em>'Etzba'</em> (H676) is the finger, the instrument of pointing and precision. The binding of instruction on the fingers extends the Shema-metaphor (Deut 6:8: bind on your hand) to a new context: the father&rsquo;s teaching is to be as constantly present as one&rsquo;s own fingers. The physical, embodied quality of this metaphor reinforces the MKT&rsquo;s anthropology of instruction as bodily formation.</p>",
    "4": "<p><strong>'achoti</strong> — &ldquo;my sister.&rdquo; <em>'Achot</em> (H269) as a term of intimate address for wisdom is significant: in Song of Songs the beloved calls the bride &ldquo;my sister&rdquo; (4:9-10, 12; 5:1-2), suggesting an erotic register of intimacy that is deliberately activated here to counter the seductive address of the adulteress in vv16-18. The father invites the son to the most intimate possible relationship with wisdom as the competing attraction to the &ldquo;foreign woman&rdquo; (<em>'ishah zarah</em>).</p><p><strong>moda'</strong> — &ldquo;close companion, kinsman.&rdquo; <em>Moda'</em> (cf. Ruth 2:1, 3:2) is a term for the closest family member; the parallelism with &ldquo;sister&rdquo; intensifies the intimacy of the wisdom-relationship the father recommends.</p>",
    "5": "<p><strong>tishmereka me-'ishah zarah</strong> — &ldquo;she [wisdom] will guard you from the foreign/strange woman.&rdquo; <em>'Ishah zarah</em> (strange/foreign woman) is the dominant characterization of the seductress throughout chs 1-9. <em>Zarah</em> (H2114) means &lsquo;alien, strange, foreign&rsquo; — not necessarily a non-Israelite, but one outside the legitimate covenant bond. The <em>nokhriyah</em> (&lsquo;alien woman&rsquo;) in the parallel is a near-synonym emphasizing her outsider status relative to the father&rsquo;s household and instruction.</p>",
    "6": "<p><strong>be-'ad halloni</strong> — &ldquo;through my window.&rdquo; <em>Chalon</em> (H2474) is the standard window term; here the father positions himself as observer rather than participant. The narrative frame of vv6-23 is the father&rsquo;s eyewitness account (&ldquo;I saw&rdquo;) — the literary device of the reported observation lends the cautionary tale the authority of testimony. The <em>'eshnav</em> (H822, v6b, &lsquo;lattice/casement&rsquo;) refers to a window with a screening lattice.</p>",
    "7": "<p><strong>va-'er ba-peta'im</strong> — &ldquo;I discerned among the simple ones.&rdquo; <em>Bein</em> (H995) is the verb of discernment/understanding used extensively in wisdom literature; here it is the father&rsquo;s act of distinguishing. <em>Peta'im</em> (the simple, the naïve) are the category of the morally unformed who have not yet chosen wisdom or folly — vulnerable in both directions. The object of the father&rsquo;s discernment is a <em>na'ar chaser-lev</em> — &ldquo;a young man lacking heart (= mind, moral sense).&rdquo; <em>Lev</em> (heart) in Hebrew denotes the seat of thought, will, and moral judgment, not merely emotion.</p>",
    "8": "<p><strong>qoreh le-fathe'ach beithah</strong> — &ldquo;passing near the corner of her street, drawing near the entrance of her house.&rdquo; The young man&rsquo;s path description (&ldquo;in the street&rdquo;, &ldquo;in the square&rdquo;, &ldquo;near the corner&rdquo;, &ldquo;the way to her house&rdquo;) is the geography of increasingly deliberate proximity. He is not yet at her door, but he is approaching it step by step — a wisdom observation about the incremental nature of moral failure.</p>",
    "9": "<p><strong>be-'ishon layelah ve-'afelah</strong> — &ldquo;in the darkness of night and the thick darkness.&rdquo; <em>'Ishon layelah</em> reuses the <em>'ishon</em> word from v2 (the pupil of the eye), creating an ironic wordplay: the &ldquo;little man of night&rdquo; (the pupil — the organ for guarding wisdom) is now the metaphor for the deepest darkness. The darkness setting establishes the moral coding: the events of vv10-23 are hidden from public accountability, the shame-preventing community oversight of Israelite life.</p>",
    "10": "<p><strong>'eshet qedeshah</strong> — the MKT follows the note that <em>'ishah</em> here does not require the explicit translation &ldquo;prostitute&rdquo; (KJV) but rather emphasizes the guarded heart (<em>netzurat lev</em>). <em>Natsar</em> (to guard, watch, keep) applied to the heart is the wisdom vocabulary of deliberate concealment of intention — she knows what she is doing. The phrase &ldquo;dressed as a harlot&rdquo; (<em>shith zonah</em>) characterizes her appearance rather than her legal status; she may be an adulteress (cf. v19) rather than a professional prostitute.</p>",
    "11": "<p><strong>homiyah hi' ve-soreref</strong> — &ldquo;she is noisy and wayward.&rdquo; <em>Hamah</em> (H1993, to be noisy, to clamor) is used of tumultuous crowds and boiling water; the seductress&rsquo;s characteristic is her disruptive presence. <em>Sorer</em> (H5637) means &lsquo;wayward, stubborn&rsquo; — the same root used of the &ldquo;stubborn and rebellious son&rdquo; in Deut 21:18-21. The contrast with Wisdom&rsquo;s structured invitation (ch 8-9) is deliberate: Wisdom calls from the heights; Folly/the seductress lurks in the streets.</p>",
    "12": "<p><strong>'atah ba-chutz 'atah ba-rechovot</strong> — &ldquo;now outside, now in the streets, lurking at every corner.&rdquo; The omnipresence of the seductress in the public spaces of the city is part of her characterization: she is the antithesis of the domestic virtue of 31:10-31. The three-fold location description (outside, streets, corners) emphasizes her unstable and deliberately exposing presence.</p>",
    "13": "<p><strong>ve-hecheziqah bo ve-nashah lo</strong> — &ldquo;she seized him and kissed him.&rdquo; The grammatical subject of the verbs is the woman, making her the agent of the pursuit: she grabs him, she kisses him. The reversal of the expected courtship dynamic (male pursuit of female) is a deliberate element of the characterization of the seductress as one who transgresses social roles. <strong>he'ezah paneyha</strong> — &ldquo;with a brazen face&rdquo;; <em>az panim</em> is used in Prov 21:29 of the wicked man — the same characterization is applied here to the seductress.</p>",
    "14": "<p><strong>zevachim shelamim 'alai</strong> — &ldquo;peace offerings are with me; today I have paid my vows.&rdquo; The <em>shelamim</em> (peace/fellowship offering, H8002) is the category of sacrifice where the worshipper kept a portion of the meat for communal eating after the priestly portions were given. Lev 7:16-17 required this meat to be eaten within one or two days — so her statement &ldquo;today I have paid my vows&rdquo; means she has abundant fresh meat available. The seduction uses the sacrificial calendar opportunistically: religious observance becomes a pretext for immorality.</p>",
    "15": "<p><strong>yatzati liqra'techa leshacher panecha</strong> — &ldquo;I came out to meet you, to seek your face earnestly.&rdquo; The verb <em>shachar</em> (H7836, to seek earnestly, to seek at dawn) is used in wisdom literature for the diligent pursuit of wisdom itself (8:17: &ldquo;those who seek me earnestly will find me&rdquo;). The seductress deliberately mimics the vocabulary of wisdom-seeking — the verbal echo is ironic and pedagogically intentional.</p>",
    "16": "<p><strong>'erez 'arashti mitati divedim 'atun mitzrayim</strong> — &ldquo;I have spread my bed with colored blankets and fine linen from Egypt.&rdquo; <em>'Erekh</em> (to spread/arrange, used of setting out a banquet or preparing a battle array) and the Egyptian linen (<em>'etun mitzrayim</em>) invoke luxury and sophistication: these are imported goods from the dominant cultural power of the day. The material detail locates the seduction in the context of international trade and cosmopolitan wealth, making her offer appear as participation in the broader world of cultured life.</p>",
    "17": "<p><strong>naddafti mishkavi mor 'ahalim ve-qinamon</strong> — &ldquo;I have scented my bed with myrrh, aloes, and cinnamon.&rdquo; All three spices are luxury imports used in the Song of Songs (Song 3:6; 4:6, 14) as erotic fragrances. The seductress deliberately invokes the vocabulary and sensory world of legitimate marital love (the Song) to package her adulterous invitation in the most attractive possible form. <em>Mor</em> (myrrh, H4753), <em>'ahalim</em> (aloes, H174), and <em>qinamon</em> (cinnamon, H7076) together represent the full spectrum of imported aromatic luxury.</p>",
    "18": "<p><strong>nerve'eh dodim 'ad-habo'ker</strong> — &ldquo;let us drink our fill of love until morning.&rdquo; <em>Ravah</em> (to drink one&rsquo;s fill, to be saturated) is used of saturation with water; here it is applied to sexual satisfaction. <em>Dodim</em> (H1730) means &lsquo;love-making, caresses&rsquo; — the term is used throughout Song of Songs for physical love. The time-frame &ldquo;until morning&rdquo; expresses the total availability of the offer while presupposing the husband&rsquo;s extended absence (v19).</p>",
    "19": "<p><strong>ki ein ha-'ish be-beito</strong> — &ldquo;for the man is not in his house.&rdquo; The detail of the husband&rsquo;s absence is the structural hinge of the seduction: she has knowledge of his travel plans and has prepared accordingly. The Hebrew <em>ha-'ish</em> (lit. &lsquo;the man&rsquo;, using the definite article — &lsquo;her husband&rsquo;) makes the adulterous context explicit. She is not a widow or a single woman; she is using her husband&rsquo;s absence as an opportunity.</p>",
    "20": "<p><strong>tzror ha-kesef laqach be-yado</strong> — &ldquo;he has taken the money bag with him.&rdquo; The husband carries the family wealth, suggesting a prosperous household: the seductress lives in luxury (cf. v16-17) and her husband is a merchant of means. The detail <em>be-yom ha-kese' yavo' beito</em> — &ldquo;at the full moon he will return&rdquo; — uses <em>kese'</em> (H3677, full moon) to specify the extended absence. A full lunar cycle gives her a calendar-window for the affair.</p>",
    "21": "<p><strong>hittatu be-rov liqchah</strong> — &ldquo;she seduced him with her many speeches.&rdquo; <em>Natah</em> (to turn, to incline) with the sense of seduction: she turned his path. <em>Chelqat sefateyha</em> — &ldquo;by the smooth talk of her lips.&rdquo; <em>Cheleq</em> (H2506) means &lsquo;portion, smoothness, flattery&rsquo;; the same term is used in v5 for the words the seductress speaks. The smooth lips that deceive are the inverse of Wisdom&rsquo;s straight and righteous speech (8:8-9: &ldquo;all the words of my mouth are righteous; there is nothing crooked or perverse in them&rdquo;).</p>",
    "22": "<p><strong>holech 'achareyha pith'om ke-shor el-tevach yavo'</strong> — &ldquo;he followed her at once, like an ox going to slaughter.&rdquo; <em>Pith'om</em> (suddenly, immediately) is significant: the seduction works on the young man without deliberation or resistance. The ox-to-slaughter and fool-to-punishment comparisons frame the seduced young man&rsquo;s action as both his own culpability (<em>'evil</em>, H191 = &lsquo;fool&rsquo;) and his victimhood. The animal comparisons use the OT&rsquo;s standard imagery of the thoughtless victim.</p>",
    "23": "<p><strong>'ad yefallach chetz kevedo</strong> — &ldquo;until an arrow pierces his liver.&rdquo; The liver (<em>kaved</em>, H3516) in Hebrew thought is the seat of deepest inward experience (cf. Lam 2:11: &ldquo;my liver is poured out&rdquo;). An arrow through the liver is a mortal wound; the metaphor completes the animal-slaughter imagery of v22: this is not merely social embarrassment but death. The transition from &ldquo;pleasant-seeming&rdquo; to &ldquo;lethal&rdquo; without warning is the wisdom point.</p>",
    "24": "<p><strong>ushme'u-li banim</strong> — &ldquo;and now, sons, listen to me.&rdquo; The father returns from narrative to direct address; the observation of vv6-23 is now applied to the sons as direct warning. The plural &ldquo;sons&rdquo; (also in 5:7, 8:32) suggests the discourse is not merely private fatherly instruction but a formative teaching document for a wider group of students in the wisdom tradition.</p>",
    "25": "<p><strong>'al-yeshte 'el-derakheyha libecha</strong> — &ldquo;do not let your heart be drawn to her ways.&rdquo; The danger is not primarily physical proximity but internal orientation: <em>natah</em> (to turn, incline) the heart is the first movement toward disaster. The heart (<em>lev</em>) as the decision-making center means that the internal posture precedes and determines the external action. Wisdom addresses the root, not only the symptom.</p>",
    "26": "<p><strong>ki-rabbim challelim hipilah</strong> — &ldquo;for many are those she has brought low.&rdquo; The plural and the quantifier &ldquo;many&rdquo; (<em>rabbim</em>) extend the seductress beyond one dangerous woman to a pattern: she represents a type of death-inviting path that has claimed many victims. <em>Challal</em> (H2491) means &lsquo;pierced, slain&rsquo; — using the vocabulary of battlefield death for the fate of adultery&rsquo;s victims. The &ldquo;mighty ones&rdquo; (<em>'atzumim</em>, H6099) who are among her slain emphasizes that strength is no defense against this form of death.</p>",
    "27": "<p><strong>darkhei sheol beithah</strong> — &ldquo;her house is the roads of Sheol.&rdquo; The plural <em>darkei sheol</em> (roads/ways of Sheol) is distinctive: the adulteress&rsquo;s house is not a single path downward but a network of paths all leading to Sheol. The final image of &ldquo;the inner chambers of death&rdquo; (<em>chadrei mavet</em>) develops the domestic metaphor of the house: she has invited him into her house (vv11-18), but her house is a house of death. The structural inversion of wisdom&rsquo;s house (9:1: seven pillars, a prepared feast) is complete: the adulteress&rsquo;s house leads to Sheol, wisdom&rsquo;s house leads to life (9:6).</p>"
  },
  "8": {
    "1": "<p><strong>halo'-chokmah tiqra'</strong> — &ldquo;does wisdom not call out?&rdquo; The rhetorical question marks the shift from the father&rsquo;s warning about the seductress (ch 7) to Wisdom&rsquo;s own voice. <em>Chokmah</em> (H2451) and <em>tevunah</em> (understanding, H8394) are the two primary wisdom terms in Proverbs, frequently paired. Their personification as a woman calling in public inverts the adulteress&rsquo;s lurking presence in ch 7: Wisdom is not secret but public, not hidden but crying aloud at the highest and busiest points of the city.</p>",
    "2": "<p><strong>be-rosh meromim 'alei-derekh</strong> — &ldquo;on the heights above the road.&rdquo; Wisdom positions herself at the <em>meromim</em> (heights, elevated places), the road intersections, and the city gates — the three most public locations in an ancient city. The gate (<em>sha'ar</em>, v3) is the site of legal proceedings, commercial transactions, and public assemblies. Wisdom addresses the city at its points of highest traffic and greatest civic importance.</p>",
    "3": "<p><strong>le-yad she'arim le-fi-qaret</strong> — &ldquo;beside the gates, at the entrance to the city.&rdquo; <em>She'arim</em> (gates) in the plural encompasses the multiple city gates; <em>pi-qaret</em> (lit. &lsquo;the mouth of the city&rsquo;) is a phrase for the main city gate as the public mouth through which the city speaks and conducts its life. Wisdom plants herself at the &lsquo;mouth of the city&rsquo; — occupying the position of authoritative public speech.</p>",
    "4": "<p><strong>'aleichem 'ishim 'eqra'</strong> — &ldquo;to you, O men (<em>'ishim</em>), I am calling.&rdquo; <em>'Ishim</em> (H376 plural) is the masculine human; the parallel <em>bene 'adam</em> (sons/children of Adam, H120) broadens the address to all humanity without restriction. The universal address of ch 8 is in deliberate contrast to the adulteress&rsquo;s targeted seduction of one vulnerable young man; Wisdom calls everyone, without discriminating by social status.</p>",
    "5": "<p><strong>havu peta'im 'ormah</strong> — &ldquo;O simple ones, learn prudence.&rdquo; <em>Pethi</em> (simple, H6612) and <em>'evil</em> (fool, H191) are addressed directly; Wisdom does not exclude the most morally unformed. <em>'Ormah</em> (prudence, H6195) is the quality of practical wisdom that distinguishes the skilled from the naive; <em>lev</em> (heart, understanding) is what the morally empty are called to receive. The invitation is to transformation, not merely to information.</p>",
    "6": "<p><strong>shim'u ki-negidim 'adaber</strong> — &ldquo;hear, for I will speak excellent/noble things.&rdquo; <em>Negidim</em> (H5057) normally means &lsquo;leaders, princes, nobles&rsquo;; here as an adverb it means &lsquo;excellent, princely, worthy things.&rsquo; The opening of wisdom&rsquo;s discourse claims for itself the dignity of princely speech. <em>Umiftach sefatai mesharim</em> — &ldquo;and the opening of my lips will be right things&rdquo; (<em>mesharim</em>, uprightness/equity). The twin claim: noble content and right character.</p>",
    "7": "<p><strong>emet yehegeh chikki</strong> — &ldquo;my palate meditates truth.&rdquo; <em>'Emet</em> (H571, truth/faithfulness) is the first named quality of wisdom&rsquo;s speech. The verb <em>hagah</em> (H1897, to meditate, mutter, moan — used of the sound a lion makes over its prey and of one who meditates the Torah day and night in Ps 1:2) implies that truth is not merely spoken but internalized and continually turned over. <em>To'avat sefatai resha'</em> — &ldquo;wickedness is an abomination to my lips&rdquo;: <em>to'avah</em> (abomination) is the strongest term for moral revulsion in the OT.</p>",
    "8": "<p><strong>be-tzedeq kol-'imrei-fi</strong> — &ldquo;all the words of my mouth are in righteousness.&rdquo; <em>Tzedeq</em> (H6664, righteousness, justice) applied to speech means that wisdom&rsquo;s discourse aligns with the moral order of the created world. <em>'Ein bahem niftal ve-'iqesh</em> — &ldquo;there is nothing twisted or crooked in them.&rdquo; <em>Niftal</em> (twisted, H6617) and <em>'iqesh</em> (H6141, crooked, perverse) are the two terms for speech that deviates from straight moral truth. Wisdom&rsquo;s self-description as the straight-speaking voice is the counterpart to the seductress&rsquo;s <em>chelqat sefatayim</em> (smooth/flattering lips, 7:21).</p>",
    "9": "<p><strong>kullam nekochim le-meivin</strong> — &ldquo;they are all straightforward to the one who understands.&rdquo; <em>Nakach</em> (H5228, straight, correct, right before one) is used elsewhere of direct, unmediated confrontation with reality. The condition &ldquo;to the one who understands&rdquo; (<em>meivin</em>) introduces the epistemological circularity of wisdom: wisdom&rsquo;s speech is plain to those who already have wisdom, and opaque to those who do not. This is the wisdom tradition&rsquo;s version of the Johannine &ldquo;whoever is of the truth hears my voice&rdquo; (John 18:37).</p>",
    "10": "<p><strong>qechu musari ve-'al-kasef</strong> — &ldquo;take my instruction and not silver.&rdquo; The comparison of wisdom to precious metals is a sustained motif (8:10, 19; 3:14-15; 16:16). <em>Musar</em> (H4148, discipline/instruction, often painful) is paired with <em>da'at</em> (knowledge, H1847) as the two forms of wisdom acquisition: the formative discipline of instruction and the cognitive grasp of knowledge. The claim that these exceed silver (<em>keseph</em>) and gold (<em>charuts</em>, refined/choice gold) is a value-claim about the hierarchy of human goods.</p>",
    "11": "<p><strong>ki tovah chokmah mipeniniym</strong> — &ldquo;for wisdom is better than jewels.&rdquo; <em>Peninim</em> (H6443) are the most precious gems — red corals or pearls (also in 3:15 and 31:10, where the excellent wife is &ldquo;more precious than peninim&rdquo;). The linking of the wisdom comparison to the excellent wife comparison is not accidental: the man who has wisdom has the equivalent of the best possible wife. <em>Kol-chafatzim lo' yishvu-vah</em> — &ldquo;and nothing desirable compares to her&rdquo;: the comprehensive claim.</p>",
    "12": "<p><strong>'ani chokmah shakhanti 'ormah</strong> — &ldquo;I, wisdom, have made prudence my dwelling.&rdquo; The verb <em>shakan</em> (to dwell, to tabernacle — the root of <em>mishkan</em>, the tabernacle of Moses) applied to wisdom&rsquo;s co-habitation with <em>'ormah</em> (prudence) describes an intimate domestic relationship. Wisdom and prudence share the same house. <em>Da'at mezimmot emtza'</em> — &ldquo;and I find knowledge and discretion.&rdquo; <em>Mezimmot</em> (H4209, discretion, prudent planning) is the wisdom capacity to plan carefully.</p>",
    "13": "<p><strong>yir'at YHWH seno'-ra'</strong> — &ldquo;the fear of the LORD is hatred of evil.&rdquo; The definition of <em>yir'at YHWH</em> (fear of the LORD, the most common wisdom formula) here is behavioral rather than affective: it consists in hating evil (<em>ra'</em>, H7451). The three parallel objects of hatred — <em>ge'ah</em> (pride), <em>ga'on</em> (arrogance), <em>derekh ra'</em> (the evil way), and <em>peh tahpukhot</em> (the perverse mouth) — identify the enemies of wisdom. Hatred of pride is the disposition that characterizes those who truly fear YHWH.</p>",
    "14": "<p><strong>li 'etzah ve-tushiyah</strong> — &ldquo;with me are counsel and wisdom.&rdquo; <em>Tushiyah</em> (H8454) is a term for effective wisdom, sound judgment, or perhaps the deeper &ldquo;abiding reality&rdquo; (BDB) of wisdom — the stable foundation that makes it competent. The accumulation of wisdom-terms in vv14-16 (<em>'etzah, tushiyah, binah, gevurah</em>) amounts to a comprehensive claim that all forms of effective human thinking and power belong to wisdom.</p>",
    "15": "<p><strong>bi melakhim yimloku</strong> — &ldquo;by me kings reign.&rdquo; The political application of wisdom claims that legitimate rule is founded on wisdom rather than on force or heredity. <em>Choqeqim</em> (rulers who decree, H2710) and <em>rozenim</em> (princes, H7336) are the two categories of human authority; both exercise their authority properly only through wisdom. The grounding of political order in divine wisdom is the OT&rsquo;s consistent teaching (cf. Rom 13:1&rsquo;s governance language has this wisdom tradition as background).</p>",
    "16": "<p><strong>bi sarim yasoru</strong> — &ldquo;by me princes govern.&rdquo; The parallel to v15 extends the claim from kings to the wider class of officials and nobles. <em>Kol shoftei tzedeq</em> — &ldquo;all just judges&rdquo; — identifies the criterion of legitimate judicial authority as <em>tzedeq</em> (justice/righteousness): the judiciary that aligns with wisdom&rsquo;s moral order is the genuinely authoritative judiciary.</p>",
    "17": "<p><strong>'ani 'ohavai 'ehav</strong> — &ldquo;I love those who love me.&rdquo; The reciprocal love-language of wisdom is striking: <em>'ahav</em> (H157, love) is used mutually. Wisdom does not merely reward or recognize her seekers — she loves them. The parallel <em>meshachamai yimtza'uni</em> — &ldquo;those who seek me earnestly will find me&rdquo; — uses <em>shachar</em> (to seek at dawn, to seek diligently, H7836), the same verb that the seductress in 7:15 used to describe her diligent search for the young man. Wisdom claims back the vocabulary of diligent seeking for herself.</p>",
    "18": "<p><strong>'osher ve-khavod 'itti</strong> — &ldquo;wealth and honor are with me.&rdquo; Wisdom&rsquo;s material claims are not ethereal: she offers <em>'osher</em> (wealth, H6239) and <em>kavod</em> (honor/glory, H3519) as real goods that her presence brings. <em>Hon 'atiq ve-tzedaqah</em> — &ldquo;enduring riches and righteousness&rdquo;: <em>'atiq</em> (H6276, enduring, ancient) qualifies the wealth as lasting rather than transient. The combination of material wealth and righteousness in wisdom&rsquo;s offer is the OT&rsquo;s consistent portrait of the flourishing life.</p>",
    "19": "<p><strong>tov peri 'mitzahav ufaz</strong> — &ldquo;my fruit is better than gold, even fine gold.&rdquo; <em>Paz</em> (H6337, fine gold, refined gold) is the highest quality of gold in the OT vocabulary. The metaphor of wisdom as a tree bearing fruit was established in 3:18 (&ldquo;she is a tree of life to those who grasp her&rdquo;); here the fruit claim is made comparatively: wisdom&rsquo;s fruit exceeds the highest material wealth. The MKT&rsquo;s translation &ldquo;my fruit&rdquo; captures the organic growth-metaphor of wisdom&rsquo;s productive output.</p>",
    "20": "<p><strong>be-'orach tzedaqah 'ahalekh</strong> — &ldquo;in the path of righteousness I walk.&rdquo; Wisdom personalizes the path-metaphor: she herself walks the righteous path, which is why following her constitutes walking it. <em>Derakhei mishpat</em> — &ldquo;in the ways of justice&rdquo; — the MKT renders <em>mishpat</em> (H4941, justice, just ordinance) as its legal-relational meaning: the structuring of reality according to right relationship. Wisdom&rsquo;s path is not merely good advice but the alignment of one&rsquo;s life with the moral order of creation.</p>",
    "21": "<p><strong>le-hanchil 'ohavai yesh</strong> — &ldquo;giving a real inheritance to those who love me.&rdquo; <em>Yesh</em> (H3426) means &lsquo;substance, that which is&rsquo; — the concrete reality of existence as opposed to illusion or vanity. Wisdom&rsquo;s gift to those who love her is substantial existence: <em>'otzaroteihem 'amalle'</em> — &ldquo;and filling their storehouses.&rdquo; The image of filled treasuries as wisdom&rsquo;s result is the OT&rsquo;s way of saying that wisdom produces a life of genuine abundance, not the false abundance promised by the adulteress.</p>",
    "23": "<p><strong>me-'olam nissakhti me-rosh</strong> — &ldquo;I was set up from of old, from the beginning.&rdquo; <em>Nassakh</em> (H5258 in Niphal = to be poured, established, installed) may draw on the imagery of a king&rsquo;s installation; the parallel <em>me-rosh</em> (from the beginning) and the preceding verse&rsquo;s claim to pre-creational existence make this the formal claim to eternal appointment. Before the first act of creation, wisdom was installed in her office. The parallel with Ps 2:6 (&ldquo;I have installed my king on Zion&rdquo;) suggests a royal installation metaphor.</p>",
    "24": "<p><strong>be-ein tehomot cholalti</strong> — &ldquo;when there were no depths, I was brought forth.&rdquo; <em>Cholal</em> (H2342 Polal = to be brought forth, to writhe in labor — a birthing verb) introduces the birth metaphor that dominates vv24-25: wisdom is not merely appointed (v23) but born. <em>Tehomot</em> (the deep waters, H8415 — the term of Gen 1:2&rsquo;s <em>tehom</em>) are absent at wisdom&rsquo;s birth; the primordial ocean has not yet been created when wisdom comes into being. The absence of springs (<em>niv'ei maim</em>) and the unformed mountains confirm this pre-creational setting.</p>",
    "25": "<p><strong>lifnei gevaot chollalti</strong> — &ldquo;before the hills, I was brought forth.&rdquo; The birth-verb <em>cholal</em> repeats from v24, framing vv24-25 as a birth-diptych. <em>Gevaot</em> (hills, H1389) before they existed: the mountain landscape of the earth is post-wisdom in terms of temporal priority. The hills that are among the most ancient features of the physical world are themselves newer than wisdom&rsquo;s coming-into-being.</p>",
    "26": "<p><strong>'ad lo' 'asah 'eretz ve-chutzot</strong> — &ldquo;before he had made the earth and the fields.&rdquo; The verse catalogs what had not yet been made at wisdom&rsquo;s appearance: the earth (<em>'eretz</em>), the open fields (<em>chutzot</em>), and the beginning of the dust of the world (<em>ro'sh 'afrot tevel</em>). <em>Tevel</em> (H8398) is the inhabited world, the productive earth — its first dust is described as younger than wisdom. The comprehensiveness of the pre-creational claim reaches its fullest expression in this verse.</p>",
    "27": "<p><strong>be-hakino shamayim sham 'ani</strong> — &ldquo;when he established the heavens, I was there.&rdquo; The eyewitness claim (&ldquo;I was there&rdquo;) sets wisdom as the observer-participant of creation. <em>Chug</em> (H2329, circle/vault — the circle drawn on the face of the deep) is the term for the vault of the sky; wisdom watches the creative act of inscribing the cosmic circle. The combination of &ldquo;was there&rdquo; and the active watching establishes wisdom as not merely pre-existent but present-at-creation.</p>",
    "28": "<p><strong>be-'ammetz shechaqim mima'al</strong> — &ldquo;when he made the skies firm above.&rdquo; <em>'Ametz</em> (H553, to make strong, confirm) applied to the clouds above establishes the structural stability of the atmosphere; <em>'ain 'ain tehom</em> — &ldquo;when the fountains of the deep were fixed.&rdquo; The <em>tehom</em> of v24 reappears: the deep that did not exist when wisdom was born is now being organized and fixed. Wisdom witnesses the taming of the primordial waters.</p>",
    "29": "<p><strong>be-sumu la-yam chuqo</strong> — &ldquo;when he set a boundary for the sea.&rdquo; <em>Choq</em> (H2706, the fixed boundary, the statute/decree) applied to the sea is the decree-metaphor for the order imposed on chaos: the waters must not transgress their boundary (<em>pi lo' ya'avru</em> — &ldquo;that the waters should not transgress his command&rdquo;). <em>Be-chuqqo mosedei 'aretz</em> — &ldquo;when he marked out the foundations of the earth.&rdquo; The same decree-term (<em>choqo</em>) governs both sea and earth-foundation: creation is ordered by statutory decree.</p>",
    "30": "<p><strong>'ehyeh 'etzlo 'amon</strong> — &ldquo;I was beside him, the master craftsman.&rdquo; <em>'Amon</em> (H525) is the most debated term in Proverbs 8. The two primary options are: (a) <em>'amon</em> as craftsman/artisan/skilled worker (cognate with Akkadian <em>ummanu</em>, &lsquo;craftsman&rsquo;; cf. Jer 52:15 use of the related <em>'aman</em>); (b) <em>'amon</em> as ward/nursling, the little child being reared (cf. Num 11:12; the MT pointing would require <em>'amun</em> for this reading). The MKT adopts &lsquo;master craftsman&rsquo; as fitting the active participatory role in creation. <em>Va-'ehyeh sha'ashu'im yom yom</em> — &ldquo;I was his daily delight&rdquo;: <em>sha'ashu'im</em> (H8191, delights/joys) is a plural of intensity; wisdom is what delights YHWH in the act of creation.</p>",
    "31": "<p><strong>mesacheqet be-tevel 'artzo</strong> — &ldquo;rejoicing in the world he had made.&rdquo; <em>Sachaq</em> (to play, rejoice, dance — used of children at play and of David dancing before the ark in 2 Sam 6:21) describes wisdom&rsquo;s disposition at creation as joyful delight in the work. <em>Ve-sha'ashu'ai 'et bene 'adam</em> — &ldquo;my delight was in the children of humanity.&rdquo; The final clause shifts wisdom&rsquo;s delight from the creation (<em>tevel</em>) to the creature (<em>bene 'adam</em>): the world delights wisdom, but the human beings in it are the specific object of her delight. This is the wisdom tradition&rsquo;s most direct statement of divine love for humanity as such.</p>",
    "32": "<p><strong>ve-'ata banim shim'u-li</strong> — &ldquo;and now, sons, listen to me.&rdquo; The transition from the cosmic Wisdom-poem (vv22-31) back to direct address is abrupt and deliberate: the eternal and cosmic character of wisdom makes the father&rsquo;s instruction more urgent, not less. The word <em>'ashrei</em> (blessed, H835 — the same term that opens the Psalter in Ps 1:1) appears twice in vv32-34, framing the invitation to wisdom as access to the blessed life that the Psalter describes.</p>",
    "33": "<p><strong>shim'u musar ve-chakemu</strong> — &ldquo;hear instruction and be wise.&rdquo; <em>Musar</em> (H4148, discipline, instruction through correction) is the term for the formative, often painful, process of wisdom acquisition. <em>Ve-'al-tifrau'</em> — &ldquo;and do not reject it.&rdquo; The negative command (<em>para'</em>, H6544, to let loose, to neglect, to become unruly) frames wisdom-rejection as a loosening of the formation that wisdom provides — the wisdom tradition&rsquo;s anthropology of instruction as constraint that liberates.</p>",
    "34": "<p><strong>'ashrei 'adam shome'a li</strong> — &ldquo;blessed is the man who listens to me.&rdquo; The second <em>'ashrei</em> clause specifies the practice: daily attendance at wisdom&rsquo;s doors (<em>meshoqed 'al-daltotai yom yom</em>, &ldquo;watching daily at my doors&rdquo;). <em>Meshaqed</em> (H8245, to watch, to keep vigil, to be sleepless) is the intensity-verb of diligent waiting; wisdom&rsquo;s blessing is given to those who wait at her threshold every day. The image of wisdom&rsquo;s house with gates and doorposts anticipates ch 9&rsquo;s Wisdom-house with its seven pillars.</p>",
    "35": "<p><strong>ki motz'i matza' chayyim</strong> — &ldquo;for the one who finds me finds life.&rdquo; <em>Motze'i</em> (to find, to encounter) and <em>chayyim</em> (life, H2416) form the central equation of Proverbs&rsquo; wisdom theology: wisdom = life. <em>Va-yafoq ratzon mei-YHWH</em> — &ldquo;and obtains favor from the LORD&rdquo;: <em>ratzon</em> (H7522, acceptance, favor, will) from YHWH is the theological goal toward which wisdom mediates. Finding wisdom is finding life; finding life is finding YHWH&rsquo;s favor. The three terms (wisdom, life, divine favor) are presented as a single package.</p>",
    "36": "<p><strong>ve-chot'i chomes nafsho</strong> — &ldquo;but he who misses me harms himself.&rdquo; <em>Chata'</em> (H2398) is typically &lsquo;to sin&rsquo; but here means &lsquo;to miss, to fail to hit the target&rsquo; — the concrete, pre-theological meaning of the sin vocabulary. The one who misses wisdom does violence (<em>chamas</em>, H2554) to his own life (<em>nafsho</em>). <em>Kol-mesana'ai 'ahavu mavet</em> — &ldquo;all those who hate me love death.&rdquo; The antithesis of the love-and-find-life equation (v35): hatred of wisdom is equivalent to love of death. The stark binary of wisdom/life versus folly/death is the pervasive structure of Proverbs&rsquo; moral universe.</p>"
  },
  "9": {
    "1": "<p><strong>chokmah banta beitah</strong> — &ldquo;Wisdom has built her house.&rdquo; The shift to perfective aspect (<em>baneta</em>, perfect) grounds the narrative: Wisdom&rsquo;s house already exists, complete, ready to receive guests. <em>Chatzevah 'ammudeyha shiv'ah</em> — &ldquo;she has hewn her seven pillars.&rdquo; <em>Chatzav</em> (H2672, to hew, cut stone) suggests deliberate architectural labor; the seven pillars (<em>'amudim</em>, H5982) are the structural foundation of the building. Seven in Hebrew numerology signifies completeness. The Wisdom-house is the designed-and-built environment for the wisdom-life; its seven pillars have been interpreted as the seven books of the Torah, the seven days of creation, or simply completeness of preparation.</p>",
    "2": "<p><strong>tavchah tivchah</strong> — &ldquo;she has slaughtered her slaughter.&rdquo; The intensive form (<em>tavchah tivchah</em>, the cognate object construction) emphasizes the abundance and completeness of the preparation: the feast is not incidental but central. <em>Maskhah yeinah</em> — &ldquo;she has mixed her wine&rdquo;: wine mixed with spices or water was the standard form for a feast. The parallel between Wisdom&rsquo;s feast (slaughtered meat, mixed wine, prepared table) and the shelamim-feast of the adulteress in 7:14 is deliberately inverted: both offer a banquet, but wisdom&rsquo;s leads to life and the seductress&rsquo;s leads to Sheol.</p>",
    "3": "<p><strong>shalachah na'aroteyha</strong> — &ldquo;she has sent out her servant girls.&rdquo; The plural <em>na'arot</em> (servant girls, attendants) makes wisdom&rsquo;s household a substantial establishment. The servants call from the <em>gappei meromei qaret</em> — the &ldquo;heights of the city&rdquo; (literally &lsquo;the wings/highest points of the city&rsquo;). The elevated calling-point ensures maximum public visibility and reach — wisdom&rsquo;s invitation is issued from the most prominent position available.</p>",
    "4": "<p><strong>mi-peti yasur hennah</strong> — &ldquo;whoever is simple, let him turn in here.&rdquo; The address to the <em>peti</em> (simple, naive, H6612) is the same as in 8:5; wisdom&rsquo;s invitation is first directed to the most morally unformed. <em>Chasar-lev</em> — &ldquo;lacking heart/mind&rdquo; — the phrase from 7:7 recurs: the naïve young man who was vulnerable to the adulteress is now the target of wisdom&rsquo;s specific invitation. The parallel between the two invitations (ch 9:4 = ch 9:16) is structural: both Wisdom and Folly use the same opening invitation-formula.</p>",
    "5": "<p><strong>lechemu be-lachmiy</strong> — &ldquo;come, eat of my bread.&rdquo; The invitation to eat wisdom&rsquo;s bread and drink her wine is the fullest expression of the feast metaphor in Proverbs. <em>Sheitu be-yayin masakhti</em> — &ldquo;drink of the wine I have mixed.&rdquo; The bread and wine of wisdom&rsquo;s banquet are the material elements of the feast that lead to life; the later NT eucharistic resonances are not the text&rsquo;s intention but arise from this shared symbolic vocabulary of the feast that transforms and sustains life.</p>",
    "6": "<p><strong>'izvu peta'im vi-chiyu</strong> — &ldquo;leave your simple ways and live.&rdquo; The imperative <em>'izvu</em> (H5800, forsake, leave behind) applied to the <em>peta'im</em> (simple ways, the path of the naïve) frames wisdom&rsquo;s invitation as requiring the abandonment of a prior way of life. <em>Vi-chiyu</em> — &ldquo;and live&rdquo; — the life-promise is the direct consequence of leaving simpleness behind. <em>Ve-'ishru be-derekh binah</em> — &ldquo;and walk in the way of understanding&rdquo;: <em>'ashar</em> (H833, to go straight, to walk happily, to call blessed) is the same root as <em>'ashrei</em> (blessed); to walk in understanding&rsquo;s way is itself the blessed life.</p>",
    "7": "<p><strong>yoser letz laqach lo qalon</strong> — &ldquo;whoever corrects a mocker gets dishonor for himself.&rdquo; <em>Meyasser</em> (H3256, to discipline, instruct, correct) directed at <em>letz</em> (H3887, the mocker/scoffer — the one who has made mockery a settled disposition) produces <em>qalon</em> (H7036, dishonor, shame) for the one who corrects. The wisdom tradition has a sober realism about the limits of instruction: it does not work on those who have chosen contempt as a lifestyle. <em>Umochiah le-rasha' mumo</em> — the one who reproves the wicked gets his <em>mum</em> (blemish/fault) thrown back at him.</p>",
    "8": "<p><strong>'al-tokach letz pen-yisne'eka</strong> — &ldquo;do not rebuke a mocker or he will only hate you.&rdquo; The prohibition is wisdom&rsquo;s recognition that the receptivity of the addressee is a precondition of effective instruction. <em>Hokach le-chakham ve-ye'ahavekha</em> — &ldquo;rebuke a wise person and he will love you.&rdquo; The contrast is stark: the same act (rebuke) produces hatred in the mocker and love in the wise person. The wise person&rsquo;s love-response to correction is the mark of genuine wisdom: he receives the rebuke as a gift rather than an insult.</p>",
    "9": "<p><strong>ten le-chakham ve-yecham 'od</strong> — &ldquo;give to a wise person and he will be wiser still.&rdquo; The self-compounding nature of wisdom: <em>chakham</em> (wise) receiving instruction becomes <em>yacham 'od</em> (wiser still). <em>Hoda' le-tzaddiq ve-yoseph leqach</em> — &ldquo;instruct a righteous person and he will increase in learning.&rdquo; <em>Tzaddiq</em> (righteous, H6662) as a near-synonym of <em>chakham</em> (wise) in this parallel confirms the wisdom tradition&rsquo;s equation of moral rectitude and cognitive wisdom: they are the same quality from different angles.</p>",
    "10": "<p><strong>techillat chokmah yir'at YHWH</strong> — &ldquo;the fear of the LORD is the beginning of wisdom.&rdquo; This is the thematic summary of Proverbs (cf. 1:7: &ldquo;the fear of the LORD is the beginning of knowledge&rdquo;). <em>Techillat</em> (H8462, beginning, first principle — used of the beginning of a journey or the principal element of something) implies both temporal priority and logical foundationality: wisdom begins with and is grounded in <em>yir'at YHWH</em>. <em>Ve-da'at qedoshim binah</em> — &ldquo;and knowledge of the Holy One is understanding.&rdquo; <em>Qedoshim</em> (the Holy One/holy ones, H6918 plural) is rare as a divine title for YHWH alone; the plural may be a plural of majesty or an echo of the divine council.</p>",
    "11": "<p><strong>bi yirbu yamecha</strong> — &ldquo;through me your days will be multiplied.&rdquo; Wisdom speaks in first person again, linking the long-life promise directly to wisdom&rsquo;s presence rather than merely to wise behavior. <em>Ve-yosifu lecha shenot chayyim</em> — &ldquo;and years of life will be added to you&rdquo;: the promise is quantitative (more years) and qualitative (years of <em>chayyim</em>, true/full life). The life-promise is the consistent refrain of Proverbs&rsquo; invitation; here it is stated in the most direct form.</p>",
    "12": "<p><strong>'im-chakhamta chakhamta lakh</strong> — &ldquo;if you are wise, you are wise for yourself.&rdquo; The reflexive consequence of wisdom — it primarily benefits the one who acquires it — is a wisdom tradition motif (cf. Job 35:6-7; Prov 19:8). <em>Ve-latzta levadecha tissa'</em> — &ldquo;and if you mock, you alone will bear it.&rdquo; The isolation of the mocker is his own doing: he bears the consequences alone because he has rejected the community-forming function of wisdom. The binary of v12 (wise = benefit yourself; mock = bear it alone) expresses wisdom&rsquo;s deeply personal stakes.</p>",
    "13": "<p><strong>'eshet kesilut homiyah</strong> — &ldquo;Dame Folly is loud.&rdquo; The personification of Folly as a woman (<em>'eshet kesilot</em>, &lsquo;woman of foolishness/fools&rsquo; — a genitive of quality) creates the structural parallel to Wisdom-woman of vv1-6. Both are women, both call from elevated positions (vv3,14), both address the simple (vv4,16) with the same opening formula. <em>Homiyah</em> (H1993, clamorous, noisy — the same term used of the adulteress in 7:11) links Dame Folly to the seductress. <em>Peta'yut</em> (H6612, simplemindedness) describes her character: she has the innocence-vocabulary but weaponizes it.</p>",
    "14": "<p><strong>ve-yashevah le-fetach beitah</strong> — &ldquo;she sits at the entrance to her house.&rdquo; The contrast with Wisdom is spatial as well as moral: Wisdom&rsquo;s servants go out actively to invite (v3); Folly sits (<em>yashevah</em>) passively at her own door. <em>'Al-kisse' meromei qaret</em> — &ldquo;on a seat at the heights of the city&rdquo; — the same elevated location (<em>meromei qaret</em>) that Wisdom&rsquo;s servants use (v3). The spatial parallel is an ironic mirror: Folly occupies wisdom&rsquo;s calling-height but does so passively and deceptively.</p>",
    "15": "<p><strong>liqro' le-'ovrei-derekh</strong> — &ldquo;calling to those who pass by.&rdquo; <em>Ha-mesharim 'orchotehem</em> — &ldquo;those who are going straight on their way.&rdquo; <em>Yashir</em> (H3474, straight, upright) used of the travelers&rsquo; paths indicates that Folly&rsquo;s specific target is those who are already on a straight path — people not looking for alternative invitations. The seduction of those already walking the right path is more dangerous than the temptation of those already wandering.</p>",
    "16": "<p><strong>mi-peti yasur hennah</strong> — &ldquo;whoever is simple, let him turn in here.&rdquo; The verbatim repetition of v4&rsquo;s opening invitation (<em>mi-peti yasur hennah</em> and <em>chasar-lev</em>) is the structural climax of the two-invitation structure of ch 9: both Wisdom and Folly use identical language to extend their invitations to the same audience. The difference is in what they offer: Wisdom offers bread and wine that lead to life (vv5-6); Folly offers stolen water and secret bread that lead to Sheol (vv17-18).</p>",
    "17": "<p><strong>mayim genuvim yimtaqu</strong> — &ldquo;stolen water is sweet.&rdquo; <em>Ganav</em> (H1589, to steal) applied to water is the idiom of the forbidden secret; <em>matok</em> (H4966, sweet) captures the experiential appeal of transgression. <em>Lechem setarim yin'am</em> — &ldquo;and food eaten in secret is delicious.&rdquo; <em>Sathar</em> (H5641, hidden, secret — the verb for concealment) applied to food: the appeal of Folly is not that she offers better food than Wisdom but that the hiddenness and illicitness add a false sweetness. The wisdom tradition&rsquo;s realism: transgression feels sweet in the moment.</p>",
    "18": "<p><strong>ve-lo' yada' ki refa'im sham</strong> — &ldquo;but he does not know that the Rephaim are there.&rdquo; <em>Refa'im</em> (H7496, the shades/ghosts of the dead, those in Sheol) are the final revelation about Folly&rsquo;s house: it is populated by the dead. <em>Be-'imqei she'ol qeru'eyha</em> — &ldquo;that those she has invited are in the depths of Sheol.&rdquo; The house of Folly is not a feast-hall but Sheol itself; her invitation is an invitation to death wearing the language of delight. This final verse closes the structural envelope of chs 7-9: the adulteress&rsquo;s house leads to Sheol (7:27), and Folly&rsquo;s house is Sheol. Wisdom&rsquo;s house leads to life (9:6, 11); folly&rsquo;s house leads to death (9:18).</p>"
  }
}

def main():
    existing = load_comm('mkt-original', 'proverbs')
    merge_comm(existing, PROVERBS)
    save_comm('mkt-original', 'proverbs', existing)
    total = sum(len(vv) for vv in PROVERBS.values())
    parts = ', '.join(f'ch{ch}={len(PROVERBS[ch])}' for ch in sorted(PROVERBS, key=int))
    print(f'Proverbs 7-9 mkt-original: {total} verses written ({parts}).')

if __name__ == '__main__':
    main()
